// ============================================================
// FIX 11.1: Filter gültige Datensätze
// Erlaubt erneute Bildgenerierung nach image_qa_error,
// wenn ein neuer vollständiger Visual Prompt vorhanden ist.
// Zusätzlich kompatibel mit Force Image Refresh Schalter.
// ============================================================

const items = $input.all();

function safe(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {};
  } catch (e) {
    return {};
  }
}

function asArr(v) {
  if (Array.isArray(v)) {
    return v.filter(Boolean).map(s => String(s).trim()).filter(Boolean);
  }

  if (typeof v === 'string' && v.trim()) {
    try {
      const p = JSON.parse(v);
      if (Array.isArray(p)) {
        return p.filter(Boolean).map(s => String(s).trim()).filter(Boolean);
      }
    } catch (e) {}
  }

  return [];
}

function robustBool(v) {
  if (v === true || v === 1) return true;
  if (typeof v === 'string') {
    const s = v.trim().toLowerCase();
    return s === 'true' || s === '1' || s === 'yes';
  }
  return false;
}

const RETRYABLE_IMAGE_STAGES = new Set([
  'qa_pending',
  'qa_failed',
  'upload_failed',
  'composed'
]);

const CONTENT_READY_STAGES = new Set([
  'content_generated',
  'content_posted'
]);

const valid = items
  .filter(item => {
    const j = item.json || {};

    const visualPromptStage = safe(j.visualPromptStage);
    const contentStage = safe(j.contentStage);
    const imageStage = safe(j.imageStage);

    const promptComplete = !!(
      safe(j.imagePrompt) &&
      safe(j.imageHeadline) &&
      safe(j.imageSubline)
    );

    if (visualPromptStage !== 'prompt_ready') return false;

    const contentNormallyReady = CONTENT_READY_STAGES.has(contentStage);
    const contentRetryAllowed =
      RETRYABLE_IMAGE_STAGES.has(imageStage) &&
      visualPromptStage === 'prompt_ready' &&
      promptComplete;

    if (!contentNormallyReady && !contentRetryAllowed) return false;

    if (!safe(j.vorgangKey) || !safe(j.nextcloudFolder)) return false;

    if (!promptComplete) return false;

    if (
      !safe(j.summaryText) &&
      !safe(j.combinedText) &&
      !safe(j.kurzfassung) &&
      !safe(j.title)
    ) {
      return false;
    }

    return true;
  })
  .map(item => {
    const j = item.json || {};
    const aj = parseObj(j.analysisJson);

    const visualPromptStage = safe(j.visualPromptStage);
    const imageStage = safe(j.imageStage);
    const promptComplete = !!(
      safe(j.imagePrompt) &&
      safe(j.imageHeadline) &&
      safe(j.imageSubline)
    );

    const retryAfterImageError =
      RETRYABLE_IMAGE_STAGES.has(imageStage) &&
      visualPromptStage === 'prompt_ready' &&
      promptComplete;

    const sl = parseObj(aj.sourceLock || {});
    const va = parseObj(aj.visualAnchors || {});

    const slValidFlag = robustBool(aj.sourceLockValid);
    const vaValidFlag = robustBool(aj.visualAnchorsValid);

    const slOk = !!(
      safe(sl.sourceTopic) &&
      safe(sl.sourceConflict) &&
      asArr(sl.requiredTerms).length >= 2 &&
      asArr(sl.requiredObjects).length >= 2 &&
      safe(sl.requiredAction) &&
      slValidFlag
    );

    const vaOk = !!(
      safe(va.satireThemaKonkret) &&
      safe(va.satireKonfliktKonkret) &&
      asArr(va.visualPflichtobjekte).length >= 2 &&
      safe(va.visualPflichthandlung) &&
      safe(va.visualErkennungssatz) &&
      safe(va.visualUeberzeichnung) &&
      asArr(va.visualVerboteneErsatzmotive).length >= 2 &&
      vaValidFlag
    );

    if (!slOk || !vaOk) {
      return {
        ...item,
        json: {
          ...j,
          imageConceptReady: false,
          imageConceptRepairNeeded: false,
          sharepicNeedStage: 'blocked_source_lock',
          _blockedReason: !slOk
            ? 'sourceLock unvollstaendig/ungueltig (requiredObjects/requiredAction/requiredTerms pruefen)'
            : 'visualAnchors unvollstaendig/ungueltig (visualVerboteneErsatzmotive/visualAnchorsValid pruefen)'
        }
      };
    }

    return {
      ...item,
      json: {
        ...j,
        imageConceptReady: true,
        imageConceptRepairNeeded: false,
        imageConceptRepairOrigin: retryAfterImageError
          ? 'retry_after_image_error_or_refresh_with_visual_prompt'
          : 'existing_visual_prompt',
        imageConceptRepairAttempt: 0,
        imageConceptRepairMaxAttempts: 2,
        _filterPassedReason: retryAfterImageError
          ? 'contentStage war Bildfehler/Bildlauf, aber vollstaendiger visualPromptStage=prompt_ready vorhanden'
          : 'Content fertig und visualPromptStage=prompt_ready vorhanden'
      }
    };
  });

return valid;

const j = $input.item.json || {};
function safeStr(v) { return (v === null || v === undefined) ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
  } catch (e) { return {}; }
}
function short(v, max = 900) {
  const s = safeStr(v);
  return s.length > max ? s.substring(0, max) + '…' : s;
}

const vorgangKey = safeStr(j.vorgangKey);
if (!vorgangKey) throw new Error('vorgangKey fehlt.');
if (!safeStr(j.imagePrompt)) throw new Error('imagePrompt fehlt in ' + vorgangKey);

const nextcloudFolder = safeStr(j.nextcloudFolder).replace(/\/+$/, '');
if (!nextcloudFolder) throw new Error('nextcloudFolder fehlt in ' + vorgangKey);

const instagramFolder = nextcloudFolder + '/02_reaktion/Instagram';
const basePrompt = safeStr(j.imagePrompt);
const negativeExtra = safeStr(j.imageNegativePrompt);
const imageHeadline = safeStr(j.imageHeadline);
const imageSubline = safeStr(j.imageSubline);
const imageSmallNote = '';
if (!imageHeadline) throw new Error('imageHeadline fehlt in ' + vorgangKey);
if (!imageSubline) throw new Error('imageSubline fehlt in ' + vorgangKey);

const visualJson = parseObj(j.visualJson);
const anchors = parseObj(visualJson.anchors);
const attempt = Math.max(1, Number(j.imageQaAttempt || 1));
const maxAttempts = Math.max(1, Number(visualJson.qualityGate?.maxAttempts || j.imageQaMaxAttempts || 3));
const retryFeedback = safeStr(j.imageQaFeedback || j.imageQaRetryInstruction);
const safeKey = vorgangKey.replace(/[^a-zA-Z0-9_-]/g, '_');
const imageRefreshRunId = safeStr(j.imageRefreshRunId || j._imageRefreshRunId || '');
const imageRefreshSuffix = imageRefreshRunId ? '_' + imageRefreshRunId.replace(/[^a-zA-Z0-9_-]/g, '_') : '';

const mustShow = Array.isArray(visualJson.mustShow)
  ? visualJson.mustShow
  : (Array.isArray(anchors.visualPflichtobjekte) ? anchors.visualPflichtobjekte : []);
// Topic-Priority: sourceLock > visualJson.sourceLock > analysisJson.sourceLock > satireThemaKonkret > title
// FIX 4.2/4.3: Canonical Source-Lock IMMER aus analysisJson
// visualJson.sourceLock ist nur Fallback wenn analysisJson technisch nicht lesbar
function getCanonicalSourceLock(j) {
  // 1. analysisJson.sourceLock hat immer Vorrang
  try {
    const raw = j.analysisJson;
    let aj = {};
    if (raw && typeof raw === 'object') aj = raw;
    else if (raw) aj = JSON.parse(String(raw));
    if (aj.sourceLock && aj.sourceLock.sourceTopic) {
      return { sl: aj.sourceLock, valid: aj.sourceLockValid === true || String(aj.sourceLockValid||'').trim()==='true' };
    }
  } catch(e) {}
  // 2. Nur technischer Fallback: visualJson.sourceLock (falls analysisJson nicht lesbar)
  try {
    const raw = j.visualJson;
    let vj = {};
    if (raw && typeof raw === 'object') vj = raw;
    else if (raw) vj = JSON.parse(String(raw));
    if (vj.sourceLock && vj.sourceLock.sourceTopic) {
      return { sl: vj.sourceLock, valid: false }; // visualJson-Fallback gilt nicht als validiert
    }
  } catch(e) {}
  return { sl: null, valid: false };
}
function getSourceLockMP(j, vj, anchors) {
  // imageTopicLock nur verwenden wenn bereits aus aktuellem canonical SL gebildet
  if (j.imageTopicLock && j._imageTopicLockFromCanonical === true) {
    return { topic: safeStr(j.imageTopicLock), conflict: safeStr(j.imageConflictLock) };
  }
  const { sl } = getCanonicalSourceLock(j);
  if (sl && sl.sourceTopic) return { topic: sl.sourceTopic, conflict: sl.sourceConflict || '' };
  // Kein canonical SL: nur Titel als letzter Fallback
  return {
    topic: safeStr(j.thema || j.title),
    conflict: safeStr(anchors.satireKonfliktKonkret || vj.conflictPlain || '')
  };
}
function _getSourceLockMP_UNUSED(j, vj, anchors) {
  if (j.imageTopicLock) return { topic: safeStr(j.imageTopicLock), conflict: safeStr(j.imageConflictLock) };
  if (vj.sourceLock && vj.sourceLock.sourceTopic) return { topic: vj.sourceLock.sourceTopic, conflict: vj.sourceLock.sourceConflict || '' };
  try {
    const aj = JSON.parse(j.analysisJson || '{}');
    if (aj.sourceLock && aj.sourceLock.sourceTopic) return { topic: aj.sourceLock.sourceTopic, conflict: aj.sourceLock.sourceConflict || '' };
  } catch(e) {}
  return {
    topic: safeStr(anchors.satireThemaKonkret || vj.topicPlain || j.thema || j.title),
    conflict: safeStr(anchors.satireKonfliktKonkret || vj.conflictPlain || '')
  };
}
const { sl: _canonicalSL, valid: _canonicalSLValid } = getCanonicalSourceLock(j);

// FIX 4.2: Abbruch wenn canonical Source-Lock fehlt oder ungültig
// Kein Fallback auf Titel, Thema, satireThemaKonkret oder visualJson.topicPlain
if (!_canonicalSL || !_canonicalSL.sourceTopic || !_canonicalSL.sourceConflict || !_canonicalSLValid) {
  const blockReason = !_canonicalSL
    ? 'blocked_by_source_lock: analysisJson.sourceLock fehlt oder unvollständig'
    : !_canonicalSLValid
      ? 'blocked_by_source_lock: analysisJson.sourceLockValid ist nicht true'
      : 'blocked_by_source_lock: sourceTopic oder sourceConflict fehlt';
  throw new Error(blockReason);
}

const _topicConflict = getSourceLockMP(j, visualJson, anchors);
const topicPlain = _topicConflict.topic;
const conflictPlain = _topicConflict.conflict || safeStr(visualJson.conflictPlain || anchors.satireKonfliktKonkret);
// FIX 4.3: imageTopicLock und imageConflictLock aus canonical SL setzen
const imageTopicLock = _canonicalSL ? _canonicalSL.sourceTopic : topicPlain;
const imageConflictLock = _canonicalSL ? (_canonicalSL.sourceConflict || conflictPlain) : conflictPlain;
const sourceLockJson = _canonicalSL ? JSON.stringify(_canonicalSL) : '{}';
const visibleAction = safeStr(visualJson.visibleAction || anchors.visualPflichthandlung);
const satiricalExaggeration = safeStr(visualJson.satiricalExaggeration || anchors.visualUeberzeichnung);
const recognitionSentence = safeStr(visualJson.recognitionSentence || anchors.visualErkennungssatz);
const satireMechanism = safeStr(visualJson.satireMechanism);
const whySatirical = safeStr(visualJson.whySatiricalWithoutText);

const prompt = [
  'Erstelle ein quadratisches Bild (1024x1024 Pixel) als Grundlage für ein politisches Satire-Sharepic der Partei DIE PARTEI, Kreisverband Goslar.',
  '',
  'QUALITÄTSZIEL:',
  'Das konkrete Sachthema soll durch reale Gegenstände und eine sichtbare Situation im Motiv erkennbar sein.',
  'THEMENSPERRE: Zeige ausschließlich das folgende Thema und den folgenden Konflikt. Keine zusätzlichen politischen Themen, keine austauschbare Verwaltungssatire und keine neue Zielscheibe.',
  'Headline und Subline dürfen den konkreten Konflikt erklären und die Satire vervollständigen. Entscheidend ist die verständliche Gesamtwirkung aus Text und Motiv.',
  topicPlain ? 'Konkretes Thema: ' + short(topicPlain, 500) : '',
  conflictPlain ? 'Konkreter Konflikt: ' + short(conflictPlain, 600) : '',
  mustShow.length ? 'Zwingend sichtbar: ' + mustShow.slice(0, 6).join(' | ') : '',
  visibleAction ? 'Zwingend sichtbare Handlung: ' + short(visibleAction, 600) : '',
  satiricalExaggeration ? 'Satirische Überzeichnung: ' + short(satiricalExaggeration, 600) : '',
  satireMechanism ? 'Satiremechanismus: ' + short(satireMechanism, 500) : '',
  recognitionSentence ? 'Erkennungstest: ' + short(recognitionSentence, 600) : '',
  whySatirical ? 'Satiretest ohne Text: ' + short(whySatirical, 600) : '',
  '',
  'AUFBAU DES BILDES (von oben nach unten):',
  '',
  '1. ROTER TEXTBALKEN (oberes Viertel, ca. 250px hoch):',
  '   - Hintergrundfarbe: kräftiges Rot (#b7202a)',
  '   - Headline (groß, fett, weiß, zentriert):',
  '   ' + imageHeadline,
  '   - Subline (mittelgroß, weiß, zentriert, direkt darunter):',
  '   ' + imageSubline,
  '   - Ausschließlich diese zwei Textzeilen; keine Small Note und keine Zusatzbeschriftung.',
  '   - Text exakt wie vorgegeben, korrekte deutsche Rechtschreibung.',
  '',
  '2. BITTERBÖSES SATIRISCHES MOTIV (untere drei Viertel, ca. 750px hoch):',
  '   - Inhalt: ' + basePrompt,
  '   - Groteske kommunalpolitische Satire-Illustration im halb-realistischen Karikaturstil.',
  '   - Das reale Thema muss sofort erkennbar sein; die sichtbare Überzeichnung muss eindeutig satirisch wirken.',
  '   - Große ausdrucksstarke Augen und klare Körpersprache, soweit passend.',
  '   - Goslar-/Harz-/Altstadt-Anmutung nur wenn thematisch passend.',
  '   - Keine echten Personen, keine Logos, keine Wappen.',
  '',
  'ABSOLUT VERBOTEN IM MOTIVBEREICH:',
  '   - KEIN Text, KEINE Schrift, KEINE Buchstaben, KEINE Zahlen.',
  '   - Headline und Subline nicht im Motiv wiederholen.',
  '   - Keine Beschriftungen auf Plakaten, Schildern oder Bannern.',
  '   - Kein QR-Code, keine echten Personen oder Politikergesichter.'
].filter(Boolean);

if (attempt > 1) {
  prompt.push('');
  prompt.push('VERBINDLICHER NEUVERSUCH ' + attempt + ' VON ' + maxAttempts + ':');
  prompt.push('Die vorherige Bildprüfung hat das Motiv abgelehnt. Korrigiere gezielt die folgenden Mängel:');
  prompt.push(short(retryFeedback || 'Thema und Satire waren nicht eindeutig genug erkennbar.', 1400));
  prompt.push('Headline und Subline wurden für diesen Versuch ebenfalls neu geprüft bzw. überarbeitet. Verwende exakt die aktuell vorgegebenen Textzeilen.');
  prompt.push('Erzeuge eine deutlich andere, klarere Komposition. Pflichtobjekte und Sachthema dürfen nicht verloren gehen.');
}

if (negativeExtra) {
  prompt.push('');
  prompt.push('Zusätzlich vermeiden: ' + negativeExtra);
}

return [{
  json: {
    ...j,
    vorgangKey,
    // FIX 4.3: Canonical SL fields für QA und Topic-Lock
    imageTopicLock,
    imageConflictLock,
    sourceLockJson,
    _imageTopicLockFromCanonical: true,
    nextcloudFolder,
    instagramFolder,
    imageHeadline,
    imageSubline,
    imageSmallNote,
    imagePrompt: basePrompt,
    imageNegativePrompt: negativeExtra,
    motifPrompt: prompt.join('\n'),
    filenameRaw: 'raw_' + safeKey + imageRefreshSuffix + '.png',
    filenameFinal: 'final_' + safeKey + imageRefreshSuffix + '.png',
    imageWorkflowVersion: 'sharepic-mini-v17.2-qa-retry-same-image',
    imageCreatedAt: new Date().toISOString(),
    imageQaAttempt: attempt,
    imageQaMaxAttempts: maxAttempts,
    imageQaFeedback: retryFeedback
  }
}];

const item = $input.item;
const j = item.json || {};
const bin = item.binary || {};
const binKey = Object.keys(bin).find(k => bin[k] && bin[k].mimeType);
if (!binKey) {
  const errMsg = j.error
    ? 'OpenAI Fehler: ' + (j.error.message || JSON.stringify(j.error)).substring(0, 300)
    : 'Kein Bild erhalten: ' + JSON.stringify(j).substring(0, 500);
  throw new Error(errMsg);
}
const ctx = $('Bereite MotivPrompt vor').item.json || {};
const srcBin = { ...bin[binKey] };
srcBin.fileName = ctx.filenameRaw || 'raw_image.png';
srcBin.fileExtension = 'png';
srcBin.mimeType = srcBin.mimeType || 'image/png';
return [{ json: { ...ctx, imageStage: 'raw_generated' }, binary: { rawImage: srcBin } }];

const rawItem = $input.item;
const bin = rawItem.binary || {};
const ctx = rawItem.json || {};

if (!bin.rawImage)     throw new Error('rawImage fehlt. Keys: '    + Object.keys(bin).join(', '));
if (!bin.overlayImage) throw new Error('overlayImage fehlt. Keys: ' + Object.keys(bin).join(', '));

// Overlay ist die Canvas (1080x1378).
// KI-Bild (1036x1000) wird bei x=22, y=12 eingesetzt.
// overlayImage wird als Basis (dataPropertyName) genommen,
// rawImage als Composite mit Offset x=22, y=12.

return [{
  json: {
    ...ctx,
    imageStage: 'ready_for_composite',
    compositeX: 22,
    compositeY: 12
  },
  binary: {
    rawImage:     bin.overlayImage,
    overlayImage: bin.rawImage
  }
}];

const item = $input.first();
const bin = item.binary || {};
const ctx = item.json || {};

if (!bin.rawImage) throw new Error('rawImage fehlt nach Composite. Keys: ' + Object.keys(bin).join(', '));

const vorgangKey = String(ctx.vorgangKey || '').trim();
if (!vorgangKey) throw new Error('vorgangKey fehlt.');

const instagramFolder = String(ctx.instagramFolder || '').trim().replace(/\/+$/, '');
if (!instagramFolder) throw new Error('instagramFolder fehlt.');

const finalBin = { ...bin.rawImage };
finalBin.fileName = ctx.filenameFinal || ('final_' + vorgangKey.replace(/[^a-zA-Z0-9_-]/g, '_') + '.png');
finalBin.fileExtension = 'png';
finalBin.mimeType = finalBin.mimeType || 'image/png';

const imageFinalPath = instagramFolder + '/' + finalBin.fileName;

return [{
  json: {
    ...ctx,
    filenameFinal: finalBin.fileName,
    imageFinalPath,
    imageCreatedAt: new Date().toISOString(),
    imageWorkflowVersion: ctx.imageWorkflowVersion || 'sharepic-mini-v17.2-qa-retry-same-image'
  },
  binary: { finalImage: finalBin }
}];

// FIX 4.4 (angepasst): Verwendet $('Prüfe finalImage').item - das komponierte Bild, nicht das rohe QA-Bild
// Stellt sicher dass das korrekte freigegebene Item mit binary.finalImage verwendet wird
const approvedItem = $('Prüfe finalImage').item;
if (!approvedItem || !approvedItem.binary || !approvedItem.binary.finalImage) {
  throw new Error('Stelle finalImage wieder her: finalImage aus Prüfe finalImage fehlt.');
}
if (!approvedItem.json.imageQaApproved) {
  throw new Error('Stelle finalImage wieder her: imageQaApproved ist nicht true.');
}
return [{
  json: { ...approvedItem.json, folderCreatedOrExists: true },
  binary: { finalImage: approvedItem.binary.finalImage }
}];

const upload = $input.item.json || {};
const ctxItem = $('Bereite Matrix Post vor').item;
const ctx = ctxItem.json || {};

const contentUri = upload.content_uri || upload.contentUri;

if (!contentUri) {
  throw new Error('[Matrix] Media Upload hat keine content_uri geliefert: ' + JSON.stringify(upload).substring(0, 500));
}

const filename = ctx.matrixFilename || ctx.filenameFinal || 'sharepic.png';

const matrixSendBody = {
  msgtype: 'm.image',
  body: filename,
  url: contentUri,
  info: {
    mimetype: 'image/png',
    w: 1080,
    h: 1378,
    size: ctxItem.binary?.finalImage?.fileSize || undefined
  }
};

return {
  json: {
    ...ctx,
    matrixContentUri: contentUri,
    matrixSendBody
  },
  binary: ctxItem.binary || {}
};

// Stellt finalImage und vollständigen Kontext nach dem Matrix-Post wieder her.
// Quelle: "Bereite Matrix Message vor" – dort existiert matrixContentUri bereits.
// current = Antwort von "Matrix Sende Bild" (enthält event_id falls Erfolg).

const current = $input.item.json || {};

const msgItem = $('Bereite Matrix Message vor').item;
const ctx     = msgItem.json || {};

if (!msgItem.binary || !msgItem.binary.finalImage) {
  throw new Error('[Matrix] finalImage konnte nach Matrix-Post nicht wiederhergestellt werden.');
}

return {
  json: {
    ...ctx,
    matrixEventId:  current.event_id || current.eventId || '',
    matrixPosted:   true,
    matrixPostedAt: new Date().toISOString()
  },
  binary: {
    finalImage: msgItem.binary.finalImage
  }
};

const item   = $input.item;
const j      = item.json || {};
const binary = item.binary || {};

if (!binary.finalImage) {
  throw new Error('[Matrix] finalImage fehlt für Matrix-Post.');
}

const vorgangKey = String(j.vorgangKey || '').trim();
if (!vorgangKey) {
  throw new Error('[Matrix] vorgangKey fehlt.');
}

const filenameFinal =
  j.filenameFinal ||
  ('final_' + vorgangKey.replace(/[^a-zA-Z0-9_-]/g, '_') + '.png');

return {
  json: {
    ...j,
    matrixFilename:       filenameFinal,
    // FIX 4.9: Deterministische txnId verhindert doppelte Matrix-Posts bei Wiederholungsläufen
    // txnId basiert auf vorgangKey + imageQaAttempt + finalem Dateinamen (stabil)
    matrixTxnId: (() => {
      const qaAttempt = String(j.imageQaAttempt || '1');
      const fname = String(j.filenameFinal || filenameFinal || '').replace(/[^a-zA-Z0-9_-]/g, '_');
      const base = vorgangKey.replace(/[^a-zA-Z0-9_-]/g, '_');
      return `${base}_qa${qaAttempt}_${fname}`.substring(0, 120);
    })(),
    matrixPostPreparedAt: new Date().toISOString()
  },
  binary
};

const uploadResult = $input.item.json || {};

const ctxItem = $('Stelle finalImage für Nextcloud wieder her').item;
const ctx     = ctxItem.json || {};

if (!ctx.vorgangKey) {
  throw new Error('[Nextcloud] vorgangKey fehlt nach Kontext-Wiederherstellung.');
}

// FIX 2.4: Fehler vom Fehlerausgang (continueErrorOutput) erkennen
// n8n setzt bei Fehlerausgang: json.error oder json.Error
const uploadError = uploadResult.error || uploadResult.Error || null;
const uploadStatusCode = Number(uploadResult.statusCode || uploadResult.status || 0);
const isExplicitFailure = uploadResult.success === false;

const isUploadFailed = (
  (uploadError !== null && uploadError !== undefined) ||
  (uploadStatusCode >= 400 && uploadStatusCode !== 0) ||
  isExplicitFailure
);

if (isUploadFailed) {
  return {
    json: {
      ...ctx,
      nextcloudUploaded: false,
      nextcloudUploadedAt: new Date().toISOString(),
      nextcloudUploadResult: uploadResult,
      nextcloudUploadError: String(uploadError || 'Upload fehlgeschlagen (statusCode: ' + uploadStatusCode + ')'),
      visualPromptStage: 'prompt_ready',
      imageStage: 'upload_failed'
    }
  };
}

// Erfolgreicher Upload
return {
  json: {
    ...ctx,
    nextcloudUploaded: true,
    nextcloudUploadedAt: new Date().toISOString(),
    nextcloudUploadResult: uploadResult
  }
};

function extractJson(text) {
  if (!text) return null;
  const s = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  return start >= 0 && end > start ? s.slice(start, end + 1) : null;
}

function getAiText(j) {
  if (Array.isArray(j)) j = j[0] || {};
  if (typeof j.content === 'string') return j.content;
  if (Array.isArray(j.content)) {
    const t = j.content.map(x => x?.text || x?.content || '').filter(Boolean).join('\n');
    if (t) return t;
  }
  if (j.output && Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) {
