}

// Diagnose fuer leere/nicht extrahierbare AI-Antworten: erfasst die Objektform
// (Keys + gekuerzte Werte) statt nur einen leeren Text, damit ein fehlschlagender
// Parse-Versuch im naechsten Lauf tatsaechlich auswertbar ist.
function safeShapeSummary(obj, maxLen) {
  maxLen = maxLen || 1500;
  try {
    var keys = Object.keys(obj || {});
    var shallow = {};
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i];
      var v = obj[k];
      if (typeof v === 'string') {
        shallow[k] = v.length > 200 ? ('[string ' + v.length + ' chars] ' + v.substring(0, 200)) : v;
      } else if (Array.isArray(v)) {
        shallow[k] = '[array ' + v.length + ' items]';
      } else if (v && typeof v === 'object') {
        shallow[k] = '[object keys: ' + Object.keys(v).join(',') + ']';
      } else {
        shallow[k] = v;
      }
    }
    var s = 'Antwort-Keys: [' + keys.join(', ') + '] Form: ' + JSON.stringify(shallow);
    return s.length > maxLen ? s.substring(0, maxLen) + '...' : s;
  } catch (e) {
    return 'shape-summary-failed: ' + e.message;
  }
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
  } catch (e) {
    return {};
  }
}

function asArray(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => String(x).trim()).filter(Boolean);
  if (v === null || v === undefined || v === '') return [];
  return [String(v).trim()].filter(Boolean);
}

function bool(v) {
  if (v === true || v === false) return v;
  return String(v || '').trim().toLowerCase() === 'true';
}

function hasValue(v) {
  return v !== null && v !== undefined && String(v).trim() !== '';
}

function normalizeOne(v, fallback) {
  if (!hasValue(v)) return fallback;
  const n = Number(v);
  if (!Number.isFinite(n)) return fallback;

  // Fehlertoleranz für Modelle, die dennoch 0–1 oder 0–10 liefern.
  let normalized = n;
  if (n >= 0 && n <= 1) normalized = n * 100;
  else if (n > 1 && n <= 10) normalized = n * 10;

  return Math.max(0, Math.min(100, Math.round(normalized)));
}

