function extractJson(text) {
  if (!text) return null;
  const s = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  return start >= 0 && end > start ? s.slice(start, end + 1) : null;
}

function getAiText(j) {
  if (Array.isArray(j)) j = j[0] || {};
  if (typeof j.content === 'string') return j.content;
  if (Array.isArray(j.content)) {
    const t = j.content.map(x => x?.text || x?.content || '').filter(Boolean).join('\n');
    if (t) return t;
  }
  if (j.output && Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) {
    return j.output[0].content[0].text;
  }
  if (typeof j.text === 'string') return j.text;
  if (typeof j.output_text === 'string') return j.output_text;
  if (j.message?.content) return j.message.content;
  if (j.choices?.[0]?.message?.content) return j.choices[0].message.content;
  return '';
}

