  return v === null || v === undefined ? '' : String(v).trim();
}

function normalizeText(v) {
  return safe(v)
    .toLowerCase()
    .replace(/[“”„"'`´]/g, '')
    .replace(/[^a-z0-9äöüß\-/]+/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function limitWords(v, maxWords) {
  const s = safe(v).replace(/[“”„"'`´]/g, '').replace(/\s+/g, ' ').trim();
  return s ? s.split(/\s+/).slice(0, maxWords).join(' ') : '';
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
  } catch (e) {
    return {};
  }
}

function asArray(v) {
  if (Array.isArray(v)) return v.map(x => safe(x)).filter(Boolean);
  if (!safe(v)) return [];
  try {
    const p = JSON.parse(String(v));
    if (Array.isArray(p)) return p.map(x => safe(x)).filter(Boolean);
  } catch (e) {}
  return String(v).split(/\s*\|\s*|\s*;\s*/).map(x => safe(x)).filter(Boolean);
}

function isDrawable(v) {
  const s = normalizeText(v);
  if (!s || s.length < 3) return false;
  const words = s.split(/\s+/).filter(Boolean);
  const abstract = new Set([
    'bürokratie','politik','gerechtigkeit','ungerechtigkeit','planung','verwaltung',
    'entscheidung','transparenz','gleichbehandlung','ungleichbehandlung','willkür',
    'fortschritt','stillstand','verfahren','regelung'
  ]);
  const abstractCount = words.filter(w => abstract.has(w)).length;
  return !(words.length <= 3 && abstractCount / words.length >= 0.5);
}

function containsAny(text, terms) {
  const n = normalizeText(text);
  return terms.some(term => {
    const nt = normalizeText(term);
    if (!nt) return false;
    if (n.includes(nt)) return true;
    const stem = nt.substring(0, Math.max(4, Math.floor(nt.length * 0.8)));
    return n.includes(stem);
  });
}

function conceptComplete(data, terms) {
  const mustShow = asArray(data.mustShow);
  const textBlock = safe(data.imageHeadline) + ' ' + safe(data.imageSubline);
  const motifBlock = safe(data.imagePrompt) + ' ' + mustShow.join(' ') + ' ' + safe(data.visibleAction);
  return (
    safe(data.imageHeadline).length >= 3 &&
    safe(data.imageSubline).length >= 3 &&
    safe(data.imagePrompt).length >= 80 &&
    safe(data.topicPlain).length >= 8 &&
    safe(data.conflictPlain).length >= 8 &&
    safe(data.visibleAction).length >= 10 &&
    safe(data.recognitionSentence).length >= 10 &&
    mustShow.filter(isDrawable).length >= 2 &&
    terms.length > 0 &&
    containsAny(textBlock, terms) &&
    containsAny(motifBlock, terms)
  );
}

const ai = $input.item.json || {};
const base = $('Bereite Bildkonzept-Reparatur vor').item.json || {};
const rawText = getAiText(ai);
const jsonText = extractJson(rawText);

let parsed = {};
let parseError = false;
try {
  parsed = jsonText ? JSON.parse(jsonText) : {};
  if (!jsonText) parseError = true;
} catch (e) {
  parsed = {};
  parseError = true;
}

const visualJsonOld = parseObj(base.visualJson);
const oldAnchors = parseObj(visualJsonOld.anchors);
const topicLock = safe(base.imageTopicLock);
const conflictLock = safe(base.imageConflictLock);
const terms = asArray(base.imageTopicTerms);

const oldConcept = {
  imageHeadline: limitWords(base.imageHeadline, 6),
  imageSubline: limitWords(base.imageSubline, 9),
  imagePrompt: safe(base.imagePrompt),
  imageNegativePrompt: safe(base.imageNegativePrompt),
  topicPlain: topicLock,
  conflictPlain: conflictLock,
  mustShow: asArray(visualJsonOld.mustShow || oldAnchors.visualPflichtobjekte),
  visibleAction: safe(visualJsonOld.visibleAction || oldAnchors.visualPflichthandlung),
  satiricalExaggeration: safe(visualJsonOld.satiricalExaggeration || oldAnchors.visualUeberzeichnung),
  recognitionSentence: safe(visualJsonOld.recognitionSentence || oldAnchors.visualErkennungssatz),
  satireMechanism: safe(visualJsonOld.satireMechanism),
  whySatiricalWithoutText: safe(visualJsonOld.whySatiricalWithoutText)
};

// Thema und Konflikt werden NICHT aus der KI-Antwort übernommen.
// Sie bleiben durch die zuvor festgelegten Quellenanker gesperrt.
const newConcept = {
  imageHeadline: limitWords(parsed.imageHeadline, 6),
  imageSubline: limitWords(parsed.imageSubline, 9),
  imagePrompt: safe(parsed.imagePrompt),
  imageNegativePrompt: safe(parsed.imageNegativePrompt),
  topicPlain: topicLock,
  conflictPlain: conflictLock,
  mustShow: asArray(parsed.mustShow),
  visibleAction: safe(parsed.visibleAction),
  satiricalExaggeration: safe(parsed.satiricalExaggeration),
  recognitionSentence: safe(parsed.recognitionSentence),
  satireMechanism: safe(parsed.satireMechanism),
  whySatiricalWithoutText: safe(parsed.whySatiricalWithoutText)
};

const errors = [];
if (base.imageConceptLockMissing === true) errors.push('Themen- oder Konfliktsperre fehlt');
if (parseError) errors.push('KI-Ausgabe ist kein valides JSON');
if (newConcept.imageHeadline.length < 3) errors.push('imageHeadline fehlt oder ist zu kurz');
if (newConcept.imageSubline.length < 3) errors.push('imageSubline fehlt oder ist zu kurz');
if (newConcept.imagePrompt.length < 80) errors.push('imagePrompt ist zu kurz oder fehlt');
if (newConcept.visibleAction.length < 10) errors.push('sichtbare Handlung fehlt');
if (newConcept.recognitionSentence.length < 10) errors.push('Erkennungssatz fehlt');
if (newConcept.mustShow.filter(isDrawable).length < 2) errors.push('mindestens zwei zeichnbare Pflichtobjekte fehlen');
if (terms.length === 0) errors.push('keine verbindlichen Themenbegriffe ableitbar');
if (terms.length > 0 && !containsAny(newConcept.imageHeadline + ' ' + newConcept.imageSubline, terms)) {
  errors.push('Headline/Subline enthalten keinen verbindlichen Themenbegriff');
}
if (terms.length > 0 && !containsAny(newConcept.imagePrompt + ' ' + newConcept.mustShow.join(' ') + ' ' + newConcept.visibleAction, terms)) {
  errors.push('Bildmotiv enthält keinen verbindlichen Themenbegriff');
}

const modelTopic = normalizeText(parsed.topicPlain);
const modelConflict = normalizeText(parsed.conflictPlain);
if (modelTopic && normalizeText(topicLock) && modelTopic !== normalizeText(topicLock)) {
  errors.push('KI wollte das festgelegte Thema verändern');
}
if (modelConflict && normalizeText(conflictLock) && modelConflict !== normalizeText(conflictLock)) {
  errors.push('KI wollte den festgelegten Konflikt verändern');
}

const newValid = !parseError && errors.length === 0 && conceptComplete(newConcept, terms);
const oldValid = conceptComplete(oldConcept, terms);
const attempt = Math.max(1, Number(base.imageConceptRepairAttempt || 1));
const maxAttempts = Math.max(1, Number(base.imageConceptRepairMaxAttempts || 2));

const allowOldFallback =
  !newValid &&
  attempt >= maxAttempts &&
  base.imageConceptRepairOrigin === 'image_qa_retry' &&
  oldValid;

const effective = newValid ? newConcept : (allowOldFallback ? oldConcept : newConcept);
const effectiveValid = newValid || allowOldFallback;

const visualJson = parseObj(base.visualJson);
const anchors = parseObj(visualJson.anchors);

if (effectiveValid) {
  visualJson.topicPlain = topicLock;
  visualJson.conflictPlain = conflictLock;
  visualJson.mustShow = effective.mustShow;
  visualJson.visibleAction = effective.visibleAction;
  visualJson.satiricalExaggeration = effective.satiricalExaggeration;
  visualJson.recognitionSentence = effective.recognitionSentence;
  visualJson.satireMechanism = effective.satireMechanism;
  visualJson.whySatiricalWithoutText = effective.whySatiricalWithoutText;
  visualJson.topicLock = topicLock;
  visualJson.conflictLock = conflictLock;
  visualJson.topicTerms = terms;

  anchors.satireThemaKonkret = topicLock;
  anchors.satireKonfliktKonkret = conflictLock;
  anchors.visualPflichtobjekte = effective.mustShow;
  anchors.visualPflichthandlung = effective.visibleAction;
  anchors.visualUeberzeichnung = effective.satiricalExaggeration;
  anchors.visualErkennungssatz = effective.recognitionSentence;
