  if (!visualJson.qualityGate || typeof visualJson.qualityGate !== 'object') visualJson.qualityGate = {};
  visualJson.qualityGate.maxAttempts = Math.max(1, Number(visualJson.qualityGate.maxAttempts || base.imageQaMaxAttempts || 3));
}

const qualityControl = parseObj(visualJson.qualityControl);
const revisions = Array.isArray(qualityControl.conceptRevisions) ? qualityControl.conceptRevisions : [];
revisions.push({
  attempt,
  createdAt: new Date().toISOString(),
  origin: safe(base.imageConceptRepairOrigin),
  source: safe(base.imageConceptRepairSource),
  topicLock,
  conflictLock,
  topicTerms: terms,
  applied: newValid,
  fallbackToOldConcept: allowOldFallback,
  errors,
  changeReason: safe(parsed.changeReason),
  parseError,
  rawResponse: parseError ? rawText.substring(0, 2500) : ''
});
qualityControl.conceptRevisions = revisions;
visualJson.qualityControl = qualityControl;

return {
  json: {
    ...base,
    imageHeadline: effectiveValid ? effective.imageHeadline : oldConcept.imageHeadline,
    imageSubline: effectiveValid ? effective.imageSubline : oldConcept.imageSubline,
    imagePrompt: effectiveValid ? effective.imagePrompt : oldConcept.imagePrompt,
    imageNegativePrompt: effectiveValid ? effective.imageNegativePrompt : oldConcept.imageNegativePrompt,
    visualJson: JSON.stringify(visualJson),
    satireThemaKonkret: topicLock,
    satireKonfliktKonkret: conflictLock,
    imageTopicLock: topicLock,
    imageConflictLock: conflictLock,
    imageTopicTerms: terms,
    imageConceptValid: effectiveValid,
    imageConceptRevisionApplied: newValid,
    imageConceptFallbackUsed: allowOldFallback,
    imageConceptErrors: errors,
    imageConceptErrorText: errors.join(' | '),
    imageConceptRepairCanRetry: !effectiveValid && attempt < maxAttempts,
    imageConceptRepairAttempt: attempt,
    imageConceptRepairMaxAttempts: maxAttempts,
    visualPromptStage: 'prompt_ready',
    imageStage: effectiveValid ? (base.imageFinalPath ? 'composed' : 'not_started') : 'concept_repair_failed',
    visualDecisionReason: effectiveValid
      ? (newValid
          ? 'Bildkonzept themengebunden repariert; Thema und Konflikt blieben gesperrt.'
          : 'Reparatur verworfen; vorhandenes themengebundenes Konzept wird weiterverwendet.')
      : 'Bildkonzept blockiert, weil die Themenbindung nicht sicher war: ' + (errors.join(' | ') || 'unbekannter Fehler'),
    imageWorkflowVersion: 'sharepic-mini-v17.2-qa-retry-same-image'
  }
};

const item = $input.item;
const j = item.json || {};
const bin = item.binary || {};

if (j.imageQaParseError !== true) {
  throw new Error('Technische QA-Neuprüfung wurde ohne Parsefehler aufgerufen.');
}
if (!bin.rawImage) {
  throw new Error('Technische QA-Neuprüfung: rawImage fehlt.');
}

const technicalAttempt = Math.max(2, Number(j.imageQaTechnicalAttempt || 1) + 1);
const technicalMaxAttempts = Math.max(2, Number(j.imageQaTechnicalMaxAttempts || 2));

return {
  json: {
    ...j,
    imageQaTechnicalAttempt: technicalAttempt,
    imageQaTechnicalMaxAttempts: technicalMaxAttempts,
    imageQaTechnicalCanRetry: technicalAttempt < technicalMaxAttempts,
    imageQaRecheckReason: 'Die vorherige Bildprüfungsantwort war technisch nicht als JSON lesbar. Dasselbe unveränderte Bild wird erneut geprüft.',
    visualPromptStage: 'prompt_ready',
    imageStage: 'qa_pending'
  },
  binary: {
    finalImage: bin.rawImage
  }
};

function extractJson(text) {
  if (!text) return null;
  const s = String(text)
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
  const start = s.indexOf('{');
  const end = s.lastIndexOf('}');
  return start >= 0 && end > start ? s.slice(start, end + 1) : null;
}

function getAiText(j) {
  if (Array.isArray(j)) j = j[0] || {};
  if (typeof j.content === 'string') return j.content;
  if (Array.isArray(j.content)) {
    const t = j.content.map(x => x?.text || x?.content || '').filter(Boolean).join('\n');
    if (t) return t;
  }
  if (j.output && Array.isArray(j.output) && j.output[0]?.content?.[0]?.text) {
    return j.output[0].content[0].text;
  }
  if (typeof j.text === 'string') return j.text;
  if (typeof j.output_text === 'string') return j.output_text;
  if (j.message?.content) return j.message.content;
  if (j.choices?.[0]?.message?.content) return j.choices[0].message.content;
  return '';
}

// Diagnose fuer leere/nicht extrahierbare AI-Antworten: erfasst die Objektform
// (Keys + gekuerzte Werte) statt nur einen leeren Text, damit ein fehlschlagender
// Parse-Versuch im naechsten Lauf tatsaechlich auswertbar ist.
function safeShapeSummary(obj, maxLen) {
  maxLen = maxLen || 1500;
  try {
    var keys = Object.keys(obj || {});
    var shallow = {};
    for (var i = 0; i < keys.length; i++) {
      var k = keys[i];
      var v = obj[k];
      if (typeof v === 'string') {
        shallow[k] = v.length > 200 ? ('[string ' + v.length + ' chars] ' + v.substring(0, 200)) : v;
      } else if (Array.isArray(v)) {
        shallow[k] = '[array ' + v.length + ' items]';
      } else if (v && typeof v === 'object') {
        shallow[k] = '[object keys: ' + Object.keys(v).join(',') + ']';
      } else {
        shallow[k] = v;
      }
    }
    var s = 'Antwort-Keys: [' + keys.join(', ') + '] Form: ' + JSON.stringify(shallow);
    return s.length > maxLen ? s.substring(0, maxLen) + '...' : s;
  } catch (e) {
    return 'shape-summary-failed: ' + e.message;
  }
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return p && typeof p === 'object' && !Array.isArray(p) ? p : {};
  } catch (e) {
    return {};
  }
}

function asArray(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(x => String(x).trim()).filter(Boolean);
  if (v === null || v === undefined || v === '') return [];
  return [String(v).trim()].filter(Boolean);
}

function bool(v) {
  if (v === true || v === false) return v;
  return String(v || '').trim().toLowerCase() === 'true';
}

function hasValue(v) {
  return v !== null && v !== undefined && String(v).trim() !== '';
}

function normalizeOne(v, fallback) {
  if (!hasValue(v)) return fallback;
  const n = Number(v);
  if (!Number.isFinite(n)) return fallback;

  // Fehlertoleranz für Modelle, die dennoch 0–1 oder 0–10 liefern.
  let normalized = n;
  if (n >= 0 && n <= 1) normalized = n * 100;
  else if (n > 1 && n <= 10) normalized = n * 10;

  return Math.max(0, Math.min(100, Math.round(normalized)));
}

const ai = $input.item.json || {};
const candidate = $('Bereite QA-Neuprüfung vor').item;
const base = candidate.json || {};

if (!candidate.binary?.finalImage) {
  throw new Error('Bildprüfung: finalImage des Kandidaten fehlt.');
}

const rawText = getAiText(ai);
const jsonText = extractJson(rawText);

let qa = {};
let parseError = false;
try {
  qa = jsonText ? JSON.parse(jsonText) : {};
  if (!jsonText) parseError = true;
} catch (e) {
  parseError = true;
  qa = {};
}

const visualJson = parseObj(base.visualJson);
const attempt = Math.max(1, Number(base.imageQaAttempt || 1));
const maxAttempts = Math.max(1, Number(base.imageQaMaxAttempts || visualJson.qualityGate?.maxAttempts || 3));
const technicalAttempt = Math.max(1, Number(base.imageQaTechnicalAttempt || 1));
const technicalMaxAttempts = Math.max(1, Number(base.imageQaTechnicalMaxAttempts || 2));

const topicRecognizable = bool(qa.topicRecognizable);
const conflictRecognizable = bool(qa.conflictRecognizable);
const satireRecognizable = bool(qa.satireRecognizable);
const textBlockAcceptable = qa.textBlockAcceptable !== false;

const blockers = [];
if (bool(qa.wrongTopic)) blockers.push('wrong_topic');
if (bool(qa.headlineUnreadable)) blockers.push('headline_unreadable');
if (bool(qa.sublineUnreadable)) blockers.push('subline_unreadable');
if (bool(qa.extraTextInMotif)) blockers.push('extra_text_in_motif');
if (bool(qa.identifiableRealPerson)) blockers.push('identifiable_real_person');
if (bool(qa.unsafeContent)) blockers.push('unsafe_content');
// FIX 4.5: Identische QA-Felder wie Parse Bildprüfung
const topicTooVague = bool(qa.topicTooVague);
const newTopicIntroduced = bool(qa.newTopicIntroduced);
const sourceTopicMatch = normalizeOne(qa.sourceTopicMatch, topicRecognizable ? 65 : 30);
const sourceConflictMatch = normalizeOne(qa.sourceConflictMatch, conflictRecognizable ? 65 : 30);
const requiredTermsVisibleOrNamed = asArray(qa.requiredTermsVisibleOrNamed);
const requiredObjectsVisible = asArray(qa.requiredObjectsVisible);
const requiredActionVisible = bool(qa.requiredActionVisible);
const forbiddenDriftDetected = bool(qa.forbiddenDriftDetected);

// V14.2 Fix: Der technische Retry vertraut dem Gesamturteil des Modells (qa.approved),
// statt dieselben Schwellenwert-Blocker mit Fallback-Defaults erneut anzuwenden.
// Grund: ein zweiter, unabhängiger Modellaufruf kann bei Nebenfeldern (z.B. sourceTopicMatch)
// abweichen, ohne dass sich das Bild inhaltlich geändert hat - das führte zu Ablehnung
// eigentlich guter Bilder allein durch Fallback-Werte unterhalb der Schwelle.



// Fehlende Punktwerte werden aus den booleschen Urteilen abgeleitet.
// Widersprüchliche niedrige Werte werden durch ein klares true nicht auf 0 stehen gelassen.
let topicClarity = normalizeOne(qa.topicClarity, topicRecognizable ? 70 : 45);
let conflictClarity = normalizeOne(qa.conflictClarity, conflictRecognizable ? 65 : 45);
let satireStrength = normalizeOne(qa.satireStrength, satireRecognizable ? 65 : 40);
let mustShowCoverage = normalizeOne(qa.mustShowCoverage, 55);
let visualCoherence = normalizeOne(qa.visualCoherence, 55);
let textQuality = normalizeOne(qa.textQuality, textBlockAcceptable ? 65 : 25);

if (topicRecognizable) topicClarity = Math.max(topicClarity, 60);
if (conflictRecognizable) conflictClarity = Math.max(conflictClarity, 55);
if (satireRecognizable) satireStrength = Math.max(satireStrength, 50);
if (textBlockAcceptable) textQuality = Math.max(textQuality, 55);

const missingElements = asArray(qa.missingElements);
if (missingElements.length === 0) {
  mustShowCoverage = Math.max(mustShowCoverage, 55);
}

const overallScore = Math.round(
  topicClarity * 0.25 +
  conflictClarity * 0.20 +
  satireStrength * 0.20 +
  visualCoherence * 0.15 +
  mustShowCoverage * 0.10 +
  textQuality * 0.10
);

const thresholds = {
  topicClarity: 65,
  conflictClarity: 55,
  satireStrength: 40,
  textQuality: 45,
  overallScore: 58
};

const topicPass = !bool(qa.wrongTopic) &&
  topicRecognizable &&
  topicClarity >= thresholds.topicClarity;

const conflictPass = conflictRecognizable &&
  conflictClarity >= thresholds.conflictClarity;

const satirePass = satireRecognizable ||
  satireStrength >= thresholds.satireStrength;

const textPass =
  textBlockAcceptable &&
  !bool(qa.headlineUnreadable) &&
  !bool(qa.sublineUnreadable) &&
  textQuality >= thresholds.textQuality;

const approved =
  !parseError &&
  blockers.length === 0 &&
  bool(qa.approved);

const evaluation = {
  attempt,
  checkedAt: new Date().toISOString(),
  parseError,
  approvedByModel: bool(qa.approved),
  topicRecognizable,
  conflictRecognizable,
  satireRecognizable,
  textBlockAcceptable,
  topicClarity,
  conflictClarity,
  satireStrength,
  mustShowCoverage,
  visualCoherence,
  textQuality,
  overallScore,
  blockers,
  modelNotes: {
    reason: String(qa.reason || '').trim(),
    missingElements,
    textRevisionNeeded: bool(qa.textRevisionNeeded),
    textRevisionReason: String(qa.textRevisionReason || '').trim()
  },
  retryInstruction: String(qa.retryInstruction || '').trim(),
  rawResponse: parseError ? (rawText ? rawText.substring(0, 3000) : ('[leerer AI-Text] ' + safeShapeSummary(ai))) : ''
};

const previousHistory = Array.isArray(base.imageQaHistory)
  ? base.imageQaHistory
  : (Array.isArray(visualJson.qualityControl?.history) ? visualJson.qualityControl.history : []);

const history = [...previousHistory, { ...evaluation, approved }];
const technicalCanRetry = false;
const canRetry = !parseError && !approved && attempt < maxAttempts;

const reasonParts = [];
if (parseError) reasonParts.push('Prüfausgabe nicht als JSON lesbar');
if (blockers.length) reasonParts.push('Ausschlussgründe: ' + blockers.join(', '));
if (!topicPass) reasonParts.push('Thema nicht ausreichend erkennbar (' + topicClarity + '/100)');
if (!conflictPass) reasonParts.push('Konflikt nicht ausreichend an Originalquelle gebunden (' + conflictClarity + '/100)');
if (!satirePass) reasonParts.push('Satire nicht ausreichend erkennbar (' + satireStrength + '/100)');
if (!textPass) reasonParts.push('Headline/Subline nicht ausreichend (' + textQuality + '/100)');
if (overallScore < thresholds.overallScore) {
  reasonParts.push('Gesamtwertung unter ' + thresholds.overallScore + ' (' + overallScore + '/100)');
}
if (evaluation.modelNotes.reason) reasonParts.push(evaluation.modelNotes.reason);
if (missingElements.length) reasonParts.push('Fehlende Elemente: ' + missingElements.join(', '));

const finalReason = [...new Set(reasonParts.filter(Boolean))].join(' | ') ||
  (approved ? 'Bildprüfung bestanden' : 'Bildprüfung nicht bestanden');

const retryParts = [];
if (evaluation.retryInstruction) retryParts.push(evaluation.retryInstruction);
if (evaluation.modelNotes.textRevisionNeeded && evaluation.modelNotes.textRevisionReason) {
  retryParts.push('Headline/Subline überarbeiten: ' + evaluation.modelNotes.textRevisionReason);
}
if (!retryParts.length) retryParts.push(finalReason);
const retryInstruction = retryParts.join(' | ');

const finalFailureStatus = parseError ? 'image_qa_error' : 'image_quality_failed';
const finalImageStage = approved
  ? 'qa_approved'
  : ((!parseError && !canRetry) ? 'qa_failed' : 'qa_pending');

visualJson.qualityControl = {
  version: 'robust-v5-topic-locked',
  maxAttempts,
  thresholds,
  weights: {
    topicClarity: 0.25,
    conflictClarity: 0.20,
    satireStrength: 0.20,
    visualCoherence: 0.15,
    mustShowCoverage: 0.10,
    textQuality: 0.10
  },
  approved,
  status: approved
    ? 'approved'
    : (parseError
        ? (technicalCanRetry ? 'qa_retry_required' : 'image_qa_error')
        : (canRetry ? 'retry_required' : finalFailureStatus)),
  attemptsUsed: attempt,
  lastEvaluation: { ...evaluation, approved },
  history
};

return {
  json: {
    ...base,
    visualJson: JSON.stringify(visualJson),
    imageQaApproved: approved,
    imageQaParseError: parseError,
    imageQaTechnicalAttempt: technicalAttempt,
    imageQaTechnicalMaxAttempts: technicalMaxAttempts,
    imageQaTechnicalCanRetry: technicalCanRetry,
    imageQaCanRetry: canRetry,
    imageQaAttempt: attempt,
    imageQaMaxAttempts: maxAttempts,
    imageQaNextAttempt: attempt + 1,
    imageQaHistory: history,
    imageQaResult: evaluation,
    imageQaOverallScore: overallScore,
    imageQaReason: finalReason,
    imageQaRetryInstruction: retryInstruction,
    imageQaTopicTooVague: topicTooVague,
    imageQaSourceTopicMatch: sourceTopicMatch,
    imageQaSourceConflictMatch: sourceConflictMatch,
    imageQaRequiredTermsVisible: requiredTermsVisibleOrNamed,
    imageQaRequiredObjectsVisible: requiredObjectsVisible,
    imageQaRequiredActionVisible: requiredActionVisible,
    imageQaNewTopicIntroduced: newTopicIntroduced,
    imageQaForbiddenDriftDetected: forbiddenDriftDetected,
    imageQaTextRevisionNeeded: evaluation.modelNotes.textRevisionNeeded || !textPass,
    visualPromptStage: 'prompt_ready',
    imageStage: finalImageStage
  },
  binary: {
    finalImage: candidate.binary.finalImage
  }
};

// ============================================================
// GEMEINSAME QA-FREIGABE (FIX 4.4)
// Beide erfolgreichen QA-Pfade laufen hier zusammen.
// Stellt sicher dass imageQaApproved=true und binary.finalImage vorhanden sind.
// ============================================================

const approvedItem = $input.item;
const aj = approvedItem.json || {};
const ab = approvedItem.binary || {};

if (aj.imageQaApproved !== true) {
  throw new Error('Gemeinsame QA-Freigabe: imageQaApproved ist nicht true.');
}
if (!ab.finalImage) {
  throw new Error('Gemeinsame QA-Freigabe: binary.finalImage fehlt.');
}

// Canonical Source-Lock aus dem Item übernehmen
return [{
  json: { ...aj, _qaFreigabeNode: 'Gemeinsame QA-Freigabe', _qaFreigabeAt: new Date().toISOString() },
  binary: { rawImage: ab.finalImage }
}];

// Sortierung: 1. firstseen aufsteigend, 2. volfdnr numerisch, 3. vorgangKey lexikografisch
function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}
function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}
const items = $input.all();
items.sort((a, b) => {
  const ja = a.json || {}, jb = b.json || {};
  const fa = parseDate(ja.firstseen), fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;
  const va = parseVolfdnr(ja.volfdnr), vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;
  return String(ja.vorgangKey || '').localeCompare(String(jb.vorgangKey || ''));
});
return items;

// ============================================================
// FORCE IMAGE REFRESH SCHALTER (v17_13)
// Zweck:
// - vorhandenen Visual Prompt behalten
// - alte Bild-/QA-/Upload-Ergebnisse verwerfen
// - Datensatz erneut in die Bildgenerierung geben
//
// Nutzung ausschliesslich ueber DataTable:
//   visualStatus = force_image_refresh (bzw. imageForceReset = true)
//
// FIX (Architekturpruefung 2026-07-22, Befund F11): der zusaetzliche,
// im Code hartcodierte manuelle Schalter (FORCE_REFRESH_IMAGE +
// FORCE_ONLY_VORGANG_KEY/FORCE_ONLY_VORGANGSNUMMER) wurde entfernt - er
// erforderte eine manuelle Code-Aenderung + Redeploy und war damit eine
// zweite, redundante Quelle fuer denselben Reset-Mechanismus. Der
// DB-gesteuerte Weg ueber imageForceReset bleibt unveraendert.
// ============================================================

const items = $input.all();

function safe(v) {
  return v === null || v === undefined ? '' : String(v).trim();
}

function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try {
    const p = JSON.parse(String(v));
    return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {};
  } catch (e) {
    return {};
  }
}

function safeJson(obj) {
  try { return JSON.stringify(obj || {}); } catch (e) { return '{}'; }
}

function makeRunId() {
  return new Date().toISOString()
    .replace(/[-:.TZ]/g, '')
    .slice(0, 14);
}

return items.map(item => {
  const j = item.json || {};

  const forceByDbStatus = j.imageForceReset === true;

  if (!forceByDbStatus) {
    return item;
  }

  const runId = makeRunId();
  const vj = parseObj(j.visualJson);

  // Alte QA-/Bildprüfungsdaten im visualJson entfernen, aber Prompt-Konzept behalten.
  delete vj.qualityControl;
  delete vj.lastEvaluation;
  delete vj.history;

  if (!vj.workflow || typeof vj.workflow !== 'object' || Array.isArray(vj.workflow)) {
    vj.workflow = {};
  }

  vj.workflow.visualStage = 'prompt_ready';
  vj.workflow.imageRefreshForcedAt = new Date().toISOString();
  vj.workflow.imageRefreshRunId = runId;
  vj.workflow.imageRefreshReason = 'imageForceReset field';

  return {
    ...item,
    json: {
      ...j,

      // Interne Markierung für diesen Workflowlauf
      _forceImageRefresh: true,
      _forceImageRefreshReason: 'imageForceReset field',
      imageRefreshRunId: runId,

      // Wichtig: Prompt bleibt erhalten.
      // Nur Bild-/QA-/Upload-Ergebnis wird zurückgesetzt.
      contentStage: 'content_generated',
      contentErrorReason: '',
      visualPromptStage: 'prompt_ready',
      imageStage: 'not_started',

      imageFinalPath: '',
      imageCreatedAt: '',
      imageWorkflowVersion: '',

      imageQaAttempt: 1,
      imageQaFeedback: '',
      imageQaRetryInstruction: '',
      imageQaApproved: false,
      imageQaParseError: false,
      imageQaReason: '',
      imageQaOverallScore: '',

      nextcloudUploaded: false,
      nextcloudUploadError: '',
      nextcloudUploadedAt: '',

      matrixPosted: false,
      matrixEventId: '',
      matrixContentUri: '',

      visualJson: safeJson(vj),
      visualDecisionReason: (
        (safe(j.visualDecisionReason) ? safe(j.visualDecisionReason) + ' | ' : '') +
        'Force Image Refresh: Bild/QA/Upload zurückgesetzt, vorhandener Visual Prompt wird erneut verwendet'
      )
    }
  };
});

// ============================================================
// BEGRENZE AUF NEUESTE VORGÄNGE
// Sicherheitsbremse gegen zu große Bild-Batches pro Lauf
// (Kosten/Laufzeit). "Sortiere Bild-Vorgänge" sortiert aufsteigend
// nach firstseen -> die letzten N Items sind die neuesten.
// ============================================================

const MAX_BILDER = 10;

const items = $input.all();

if (items.length <= MAX_BILDER) {
  console.log(`[Bildlimit] ${items.length} Vorgänge, Limit ${MAX_BILDER} nicht erreicht - alle werden verarbeitet.`);
  return items;
}

const limited = items.slice(-MAX_BILDER);
console.log(`[Bildlimit] ${items.length} gültige Vorgänge gefunden, auf die neuesten ${MAX_BILDER} begrenzt (${items.length - MAX_BILDER} übersprungen, laufen beim nächsten Mal erneut rein).`);

return limited;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
const j = $json;
return {
  json: {
    vorgangKey: safeStr(j.vorgangKey),
    vorgangsnummer: safeStr(j.vorgangsnummer),
    title: safeStr(j.title),
    sprengstoff: safeStr(j.sprengstoff),
    satireBrief: safeStr(j.satireBrief),
    satireAngle: safeStr(j.satireAngle),
    satirePunchlines: safeStr(j.satirePunchlines),
    imageHeadline: safeStr(j.imageHeadline),
    imageSubline: safeStr(j.imageSubline),
    pressStatementBisher: safeStr(j.pressStatement),
    absurdeForderung: safeStr(j.absurdeForderung)
  }
};

