function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
const original = $('Presseartikel Final: Baue Eingabe').itemMatching($itemIndex).json;
const raw = $json;
let text = '';
try {
  const content = raw.message?.content ?? raw.content ?? raw.text ?? '';
  const cleaned = String(content).replace(/```json/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  text = safeStr(parsed.pressStatement);
} catch (e) {}
const finalText = text || original.pressStatementBisher;
return { json: { ...original, pressStatementFinal: finalText, pressArtikelParseError: !text } };

const j = $json;
const room = '!tMRdHxOLwIKDiQlIRz:matrix.golietz.de';
const txnId = 'presse_' + Date.now() + '_' + String(j.vorgangKey||'').replace(/[^a-zA-Z0-9]/g,'').substring(0,10);
return { json: { ...j, matrixPresseRoom: room, matrixPresseTxnId: txnId } };
